<template>
    <div class="ticket_list_container">
        <!-- Header Section -->
        <div class="ticket_list_header main_header_bg_new">
            <div class="header_content">
                <div class="header_title">
                    <h5 class="mb-2">
                        <mdb-icon icon="ticket-alt" class="mr-2"/>
                        {{$t('closed_ticket_list') || 'Закрытые тикеты'}}
                    </h5>
                </div>
                <div class="header_actions">
                    <div class="search_wrapper">
                        <div class="search_input_container">
                            <mdb-icon icon="search" class="search_icon_input"/>
                            <input 
                                class="search_input_custom" 
                                v-model="search" 
                                :placeholder="$t('search_ticket_org') || 'Поиск по номеру или организации...'" 
                                type="text"
                                @input="onSearchInput"
                            />
                        </div>
                    </div>
                </div>
            </div>
        </div>

        <!-- Table Section -->
        <div class="ticket_list_table_wrapper">
            <loader v-if="loading"/>
            <div v-else class="table_container">
                <table class="ticket_table">
                    <thead>
                        <tr class="table_header">
                            <th width="50" class="text-center">№</th>
                            <th>{{$t('ticket_number')}}</th>
                            <th>{{$t('organization_name')}}</th>
                            <th>{{$t('massa')}}</th>
                            <th>{{$t('invoice_massa')}}</th>
                            <th>{{$t('percentage')}}</th>
                            <th>{{$t('price')}}</th>
                            <th>{{$t('total_price')}}</th>
                            <th>{{$t('tegirmon_hisob')}}</th>
                            <th>{{$t('note')}}</th>
                            <th>{{$t('closed_date') || 'Дата закрытия'}}</th>
                        </tr>
                    </thead>
                    <tbody>
                        <tr 
                            v-for="(row, index) in filteredList" 
                            :key="index" 
                            @click="viewTicketDetail(row.id)"
                            class="table_row"
                        >
                            <td class="text-center">
                                <span class="row_number">{{index+1}}</span>
                            </td>
                            <td>
                                <span class="">{{row.ticket_number || '-'}}</span>
                            </td>
                            <td>
                                <span class="organization_name">{{row.organization_name || '-'}}</span>
                            </td>
                            <td>
                                <span class="measure_badge">{{formatNumber(row.massa)}} кг</span>
                            </td>
                            <td>
                                <span class="measure_badge_invoice">{{formatNumber(row.invoice_massa)}} кг</span>
                            </td>
                            <td>
                                <span class="percentage_badge" :class="getPercentageClass(row.percentage)">
                                    {{formatPercentage(row.percentage)}}%
                                </span>
                            </td>
                            <td>
                                <span class="price_text">{{formatNumber(row.price)}}</span>
                            </td>
                            <td>
                                <span class="total_price_text">{{formatNumber(row.total_price)}}</span>
                            </td>
                            <td>
                                <span class="hisob_name">{{row.hisob_name || '-'}}</span>
                            </td>
                            <td>
                                <span class="note_text" :title="row.note">{{row.note || '-'}}</span>
                            </td>
                            <td>
                                <div class="date_info d-flex">
                                    <span class="date_text mr-1">
                                        {{formatDate(row.closed_date_time || row.updated_date_time)}}
                                    </span>
                                    <span class="time_text ml-1">
                                        {{formatTime(row.closed_date_time || row.updated_date_time)}}
                                    </span>
                                </div>
                            </td>
                        </tr>
                        <tr v-if="filteredList.length === 0" class="empty_row">
                            <td colspan="11" class="text-center py-4">
                                <mdb-icon icon="inbox" class="mb-2" style="font-size: 48px; color: #ccc;"/>
                                <p class="text-muted mb-0">{{$t('no_data') || 'Данные не найдены'}}</p>
                            </td>
                        </tr>
                    </tbody>
                </table>
            </div>
        </div>
    </div>
</template>

<script>
import {mdbIcon} from 'mdbvue'
export default {
    components: {
        mdbIcon,
    },
    data() {
        return {
            search: '',
            loading: false,
            ticket_list: [],
            searchTimeout: null,
        }
    },
    async mounted () {
        await this.fetchTicketList();
    },
    computed: {
        filteredList() {
            // Backend'dan kelgan ma'lumotlar allaqachon filter qilingan
            return this.ticket_list || [];
        }
    },
    methods: {
        onSearchInput() {
            // Debounce qidiruv
            if (this.searchTimeout) {
                clearTimeout(this.searchTimeout);
            }
            this.searchTimeout = setTimeout(() => {
                this.fetchTicketList();
            }, 500);
        },
        async fetchTicketList() {
            try {
                this.loading = true;
                let url = this.$store.state.hostname + '/TegirmonTicket/getPaginationClosedTickets?page=0&size=100';
                
                // Agar qidiruv bo'lsa, search endpoint'ni ishlatamiz
                if (this.search && this.search.trim() !== '') {
                    url = this.$store.state.hostname + '/TegirmonTicket/getPaginationSearchClosedTickets?page=0&size=100&search=' + encodeURIComponent(this.search.trim());
                }
                
                const res = await fetch(url);
                const data = await res.json();
                this.loading = false;
                
                if(res.status == 200 || res.status == 201){
                    this.ticket_list = data.items_list || [];
                }
                else{
                    if(this.$refs.message) {
                        this.$refs.message.error('network_ne_connect')
                    }
                    this.loading = false; 
                }
                this.loading = false;
            }
            catch{
                if(this.$refs.message) {
                    this.$refs.message.error('network_ne_connect')
                }
                this.loading = false;
            }
        },
        formatNumber(num) {
            if (!num && num !== 0) return '0';
            return parseFloat(num).toFixed(1).replace(/\B(?=(\d{3})+(?!\d))/g, ' ');
        },
        formatPercentage(num) {
            if (!num && num !== 0) return '0';
            return parseFloat(num).toFixed(1);
        },
        getPercentageClass(percentage) {
            if (percentage >= 100) return 'percentage_complete';
            if (percentage >= 50) return 'percentage_medium';
            return 'percentage_low';
        },
        formatDate(dateString) {
            if (!dateString) return '-';
            const date = new Date(dateString);
            const day = String(date.getDate()).padStart(2, '0');
            const month = String(date.getMonth() + 1).padStart(2, '0');
            const year = date.getFullYear();
            return `${day}-${month}-${year}`;
        },
        formatTime(dateString) {
            if (!dateString) return '';
            const date = new Date(dateString);
            const hours = String(date.getHours()).padStart(2, '0');
            const minutes = String(date.getMinutes()).padStart(2, '0');
            return `${hours}:${minutes}`;
        },
        viewTicketDetail(ticketId) {
            this.$router.push('/ticket_detail/' + ticketId);
        }
    },
}
</script>

<style lang="scss" scoped>
.ticket_list_container {
  background: linear-gradient(135deg, #f9feff 0%, #f7fbff 100%);
  min-height: calc(100vh - 140px);
}

.ticket_list_header {
  margin-bottom: 15px;
  padding: 10px 16px;
  background: linear-gradient(135deg, #A3CBD5 0%, #456F8E 100%);
  border-radius: 8px;

  .header_content {
    display: flex;
    justify-content: space-between;
    align-items: center;
    flex-wrap: wrap;
    gap: 16px;
  }

  .header_title {
    h5 {
      color: #ffffff;
      font-weight: 600;
      display: flex;
      align-items: center;
    }
  }

  .header_actions {
    display: flex;
    align-items: center;
    gap: 12px;
    flex-wrap: wrap;
  }

  .search_wrapper {
    position: relative;
    min-width: 300px;

    .search_input_container {
      position: relative;
      display: flex;
      align-items: center;
      background: rgba(255, 255, 255, 0.15);
      border: 1px solid rgba(255, 255, 255, 0.3);
      border-radius: 8px;
      padding: 0 12px;
      min-height: 29px;
      transition: all 0.3s ease;

      &:hover {
        background: rgba(255, 255, 255, 0.2);
        border-color: rgba(255, 255, 255, 0.4);
      }

      &:focus-within {
        background: rgba(255, 255, 255, 0.25);
        border-color: rgba(255, 255, 255, 0.5);
        box-shadow: 0 2px 8px rgba(0, 0, 0, 0.1);
      }

      .search_icon_input {
        color: rgba(255, 255, 255, 0.9);
        font-size: 16px;
        margin-right: 10px;
        flex-shrink: 0;
      }

      .search_input_custom {
        flex: 1;
        background: transparent;
        border: none;
        outline: none;
        color: white;
        font-size: 13px;
        padding: 5px 0;
        width: 100%;

        &::placeholder {
          color: rgba(255, 255, 255, 0.7);
          font-size: 13px;
        }

        &:focus {
          outline: none;
        }
      }
    }
  }
}

.ticket_list_table_wrapper {
  background: white;
  border-radius: 12px;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.08);
  overflow: hidden;
  height: calc(100vh - 240px);
  display: flex;
  flex-direction: column;
}

.table_container {
  flex: 1;
  overflow: auto;
}

.ticket_table {
  width: 100%;
  border-collapse: collapse;
  font-size: 13px;

  .table_header {
    background: linear-gradient(135deg, #A3CBD5 0%, #456F8E 100%);
    color: white;
    position: sticky;
    top: 0;
    z-index: 10;

    th {
      padding: 7px 14px;
      font-weight: 600;
      font-size: 10px;
      text-transform: uppercase;
      letter-spacing: 0.5px;
      text-align: left;
      white-space: nowrap;

      &:first-child {
        border-top-left-radius: 12px;
      }
      &:last-child {
        border-top-right-radius: 12px;
      }
    }
  }

  .table_row {
    border-bottom: 1px solid #f0f0f0;
    transition: all 0.2s ease;
    cursor: pointer;

    &:hover {
      background: linear-gradient(90deg, rgba(163, 203, 213, 0.1) 0%, rgba(69, 111, 142, 0.05) 100%);
    }

    &:last-child {
      border-bottom: none;
    }

    td {
      padding: 5px 14px;
      vertical-align: middle;
      font-size: 12px;
    }
  }

  .row_number {
    display: inline-block;
    width: 28px;
    height: 28px;
    line-height: 28px;
    text-align: center;
    background: linear-gradient(135deg, #A3CBD5 0%, #456F8E 100%);
    color: white;
    border-radius: 50%;
    font-weight: 600;
    font-size: 11px;
  }

  .ticket_badge {
    display: inline-block;
    padding: 4px 10px;
    background: linear-gradient(135deg, #A3CBD5 0%, #456F8E 100%);
    color: white;
    border-radius: 12px;
    font-weight: 600;
    font-size: 11px;
    letter-spacing: 0.5px;
  }

  .organization_name {
    font-weight: 500;
    color: #2c3e50;
    font-size: 13px;
  }

  .measure_badge {
    display: inline-block;
    padding: 4px 10px;
    background: #e8f5e9;
    color: #2e7d32;
    border-radius: 8px;
    font-weight: 600;
    font-size: 12px;
  }

  .measure_badge_invoice {
    display: inline-block;
    padding: 4px 10px;
    background: #e3f2fd;
    color: #1565c0;
    border-radius: 8px;
    font-weight: 600;
    font-size: 12px;
  }

  .percentage_badge {
    display: inline-block;
    padding: 4px 10px;
    border-radius: 8px;
    font-weight: 600;
    font-size: 12px;
    
    &.percentage_complete {
      background: #c8e6c9;
      color: #1b5e20;
    }
    
    &.percentage_medium {
      background: #fff9c4;
      color: #f57f17;
    }
    
    &.percentage_low {
      background: #ffcdd2;
      color: #c62828;
    }
  }

  .price_text {
    font-weight: 500;
    color: #495057;
    font-size: 13px;
  }

  .total_price_text {
    font-weight: 600;
    color: #2c3e50;
    font-size: 13px;
  }

  .hisob_name {
    color: #6c757d;
    font-size: 13px;
  }

  .note_text {
    color: #6c757d;
    max-width: 200px;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
    display: inline-block;
    font-size: 13px;
  }

  .date_info {
    display: flex;
    gap: 2px;
    font-size: 13px;

    .date_text {
      font-weight: 500;
      color: #2c3e50;
      font-size: 13px;
    }

    .time_text {
      font-size: 13px;
      color: #6c757d;
    }
  }

  .empty_row {
    td {
      padding: 60px 20px;
    }
  }
}

// Responsive design
@media (max-width: 768px) {
  .ticket_list_header {
    .header_content {
      flex-direction: column;
      align-items: stretch;
    }

    .header_actions {
      flex-direction: column;
      width: 100%;

      .search_wrapper {
        width: 100%;
        min-width: auto;

        .search_input_container {
          .search_input_custom {
            font-size: 12px;
            padding: 6px 0;

            &::placeholder {
              font-size: 12px;
            }
          }

          .search_icon_input {
            font-size: 14px;
            margin-right: 8px;
          }
        }
      }
    }
  }

  .ticket_table {
    font-size: 11px;

    .table_header th,
    .table_row td {
      padding: 8px 6px;
      font-size: 11px;
    }
  }
}
</style>

